import React from "react";
import styles from "./nav-button.module.css";

interface NavButtonProps {
    href: string;
    text: string;
    imgSrc?: string;
}

const NavButton: React.FC<NavButtonProps> = ({ href, text, imgSrc }) => {
  return (
    <a className={styles.nav__button_link} href={href}>
      <button type="button" className={styles.nav__button}>
        <span className={styles.nav__button_content}>
          {imgSrc && <img src={imgSrc} alt="icon" width={10} height={10} />}
        </span>
      </button>
    </a>
  );
};

export default NavButton;
